#### **Auth Middleware Implementation** (auth.middleware.ts)
```typescript
export function requireAuth(req: Request, _res: Response, next: NextFunction): void {
  const session = req.session;

  if (!session?.userId) {
    throw new UnauthorizedError('No active session');
  }

  // Session inactivity check (30 minutes)
  const lastActivity = session.lastActivity ?? session.lastActivityAt;
  if (lastActivity !== undefined && Date.now() - lastActivity > SESSION_INACTIVITY_MS) {
    session.destroy(() => {});
    next(new UnauthorizedError('Session expired due to inactivity'));
    return;
  }

  // Populate req.userId and req.userRoles
  req.userId = session.userId;
  req.userRoles = (session.userRoles ?? session.roles ?? []) as string[];

  // Update activity timestamp
  session.lastActivity = Date.now();
  next();
}
```

#### **RBAC Middleware Implementation** (rbac.middleware.ts)
```typescript
export function requireRole(...allowedRoles: string[]): RequestHandler {
  return (req: Request, _res: Response, next: NextFunction): void => {
    const userRoles: string[] = req.userRoles ?? [];
    const hasRole = allowedRoles.some((r) => userRoles.includes(r));
    if (!hasRole) {
      throw new ForbiddenError(`Requires one of roles: ${allowedRoles.join(', ')}`);
    }
    next();
  };
}
```

#### **Available Roles** (roles.constant.ts)
```
- SYSTEM_ADMIN
- LEASING_OPS_MANAGER
- TEST_PROCTOR
- ANALYST
- STANDARD_USER
```

