1	import { DeliveryStatus, Prisma } from '@prisma/client';
2	import { prisma } from '../../config/database';
3	import { logger } from '../../logging/logger';
4	import { NotFoundError, ConflictError } from '../../shared/errors';
5	import { parsePagination, buildMeta } from '../../shared/utils/pagination.util';
6	import {
7	  isWithinQuietHours,
8	  getQuietHoursEndTime,
9	} from '../../shared/utils/quiet-hours.util';
10	import { messageQueue } from './queue/message-queue';
11	import { fileGenerator } from './delivery/file-generator';
12	import {
13	  EnqueueMessageBody,
14	  UpdateDeliveryBody,
15	  AddBlacklistBody,
16	  ListMessagesQuery,
17	  ListBlacklistQuery,
18	  UpdateQuietHoursBody,
19	} from './messaging.schemas';
20	
21	export class MessagingService {
22	  /**
23	   * Enqueue a message for delivery.
24	   *
25	   * Processing order:
26	   *  1. Render template variables (if templateId supplied)
27	   *  2. Check recipient blacklist — if suppressed, create as SUPPRESSED and return
28	   *  3. Check global quiet hours — if active, defer nextRetryAt to end of quiet window
29	   *  4. Create the queued message record
30	   *  5. If recipient user has ALSO_PACKAGE preference, generate file immediately
31	   */
32	  async enqueueMessage(data: EnqueueMessageBody) {
33	    // ── 1. Template rendering ────────────────────────────────────────
34	    let subject = data.subject ?? '';
35	    let renderedBody = '';
36	
37	    if (data.templateId) {
38	      const template = await prisma.notificationTemplate.findUnique({
39	        where: { id: data.templateId },
40	      });
41	
42	      if (!template) {
43	        throw new NotFoundError('Notification template not found');
44	      }
45	
46	      subject = this.renderTemplate(template.subjectTpl, data.variables ?? {});
47	      renderedBody = this.renderTemplate(template.bodyTpl, data.variables ?? {});
48	    } else {
49	      renderedBody = data.variables?.body ?? '';
50	    }
51	
52	    // ── 2. Blacklist check ───────────────────────────────────────────
53	    const isBlacklisted = await this.isRecipientBlacklisted(
54	      data.recipientAddr,
55	      data.channel,
56	    );
57	
58	    if (isBlacklisted) {
59	      const suppressed = await prisma.outboundMessage.create({
60	        data: {
61	          templateId: data.templateId ?? null,
62	          recipientAddr: data.recipientAddr,
63	          recipientUserId: data.recipientUserId ?? null,
64	          channel: data.channel as any,
65	          subject: subject || null,
66	          renderedBody,
67	          status: DeliveryStatus.SUPPRESSED,
68	          nextRetryAt: null,
69	        },
70	      });
71	
72	      logger.warn(
73	        { messageId: suppressed.id, recipientAddr: data.recipientAddr, channel: data.channel },
74	        'Message suppressed — recipient is blacklisted',
75	      );
76	
77	      return suppressed;
78	    }
79	
80	    // ── 3. Quiet hours check ─────────────────────────────────────────
81	    let nextRetryAt: Date = new Date();
82	
83	    const quietConfig = await this.getQuietHoursConfig();
84	    if (quietConfig && isWithinQuietHours(quietConfig, nextRetryAt)) {
85	      nextRetryAt = getQuietHoursEndTime(quietConfig, nextRetryAt);
86	      logger.info(
87	        { nextRetryAt, timezone: quietConfig.timezone },
88	        'Message delivery deferred — within quiet hours',
89	      );
90	    }
91	
92	    // ── 4. Create queued message ─────────────────────────────────────
93	    const message = await messageQueue.enqueue({
94	      templateId: data.templateId,
95	      recipientAddr: data.recipientAddr,
96	      recipientUserId: data.recipientUserId,
97	      channel: data.channel,
98	      subject: subject || null,
99	      renderedBody,
100	      nextRetryAt,
101	    });
102	
103	    logger.info({ messageId: message.id, channel: data.channel }, 'Message enqueued');
104	
105	    // ── 5. User preference: ALSO_PACKAGE → generate file now ─────────
106	    if (data.recipientUserId) {
107	      const pref = await prisma.userPreference.findUnique({
108	        where: { userId: data.recipientUserId },
109	      });
110	
111	      if (pref?.deliveryMode === 'ALSO_PACKAGE') {
112	        try {
113	          const filePath = await fileGenerator.generateMessageFile({
114	            id: message.id,
115	            recipientAddr: message.recipientAddr,
116	            channel: message.channel,
117	            subject: message.subject,
118	            renderedBody: message.renderedBody,
119	          });
120	
121	          await prisma.outboundMessage.update({
122	            where: { id: message.id },
123	            data: { fileOutputPath: filePath },
124	          });
125	
126	          logger.info(
127	            { messageId: message.id, filePath },
128	            'Package file generated due to ALSO_PACKAGE preference',
129	          );
130	        } catch (err) {
131	          logger.error({ messageId: message.id, err }, 'Failed to generate immediate package file');
132	        }
133	      }
134	    }
135	
136	    return message;
137	  }
138	
139	  /**
140	   * List messages with pagination and filtering.
141	   * Non-admin users can only see their own messages.
142	   */
143	  async listMessages(filters: ListMessagesQuery, userId: string, isAdmin: boolean) {
144	    const { skip, take, page, pageSize } = parsePagination(filters);
145	
146	    const where: Prisma.OutboundMessageWhereInput = {};
147	
148	    if (!isAdmin) {
149	      where.OR = [
150	        { recipientUserId: userId },
151	        { isFailureAlert: false },
152	      ];
153	    }
154	
155	    if (filters.status) {
156	      where.status = filters.status as DeliveryStatus;
157	    }
158	
159	    if (filters.channel) {
160	      where.channel = filters.channel as any;
161	    }
162	
163	    if (filters.recipientUserId) {
164	      where.recipientUserId = filters.recipientUserId;
165	    }
166	
167	    const [messages, total] = await Promise.all([
168	      prisma.outboundMessage.findMany({
169	        where,
170	        skip,
171	        take,
172	        orderBy: { createdAt: 'desc' },
173	      }),
174	      prisma.outboundMessage.count({ where }),
175	    ]);
