1	import { prisma } from '../../../config/database';
2	import { logger } from '../../../logging/logger';
3	
4	export class SeatAllocator {
5	  /**
6	   * Allocate a seat for a registration within a session.
7	   *
8	   * Rules:
9	   * 1. Only serviceable seats in the room are considered.
10	   * 2. Accessible seats are reserved for accessibility needs - skip them
11	   *    unless no other seats are available.
12	   * 3. Prefer a seat in a row that already has allocations for this session
13	   *    (contiguous/adjacent seating preference).
14	   * 4. If no adjacent seat is possible, pick the first available non-accessible seat.
15	   */
16	  async allocateSeats(
17	    sessionId: string,
18	    registrationId: string,
19	    roomId: string,
20	  ) {
21	    // Get all serviceable seats ordered by row then position
22	    const allSeats = await prisma.testSeat.findMany({
23	      where: { roomId, isServiceable: true },
24	      orderBy: [{ rowIdentifier: 'asc' }, { positionInRow: 'asc' }],
25	    });
26	
27	    // Get already-allocated seat IDs for this session
28	    const existingAllocations = await prisma.seatAllocation.findMany({
29	      where: { sessionId },
30	      select: { seatId: true, seat: { select: { rowIdentifier: true, positionInRow: true } } },
31	    });
32	
33	    const allocatedSeatIds = new Set(existingAllocations.map((a) => a.seatId));
34	
35	    // Filter out already-allocated seats
36	    const availableSeats = allSeats.filter((s) => !allocatedSeatIds.has(s.id));
37	
38	    if (availableSeats.length === 0) {
39	      logger.warn({ sessionId, roomId }, 'No available seats for allocation');
40	      return null;
41	    }
42	
43	    // Check which accessible seats have an AdaSeatRelease for this session
44	    // ADA seats are held unless an explicit release record exists for this session.
45	    const adaReleases = await prisma.adaSeatRelease.findMany({
46	      where: { sessionId },
47	      select: { seatId: true },
48	    });
49	    const releasedAdaSeatIds = new Set(adaReleases.map((r) => r.seatId));
50	
51	    // Separate non-accessible and accessible-but-released seats (usable by anyone)
52	    const nonAccessible = availableSeats.filter((s) => !s.isAccessible);
53	    // Accessible seats are only available to general allocation if explicitly released
54	    const accessible = availableSeats.filter(
55	      (s) => s.isAccessible && releasedAdaSeatIds.has(s.id),
56	    );
57	    // Unreleased ADA seats are last resort only when nothing else is available
58	    const unreleasedAda = availableSeats.filter(
59	      (s) => s.isAccessible && !releasedAdaSeatIds.has(s.id),
60	    );
61	
62	    // Build a set of rows that already have allocations in this session
63	    const allocatedRowPositions = new Map<string, number[]>();
64	    for (const alloc of existingAllocations) {
65	      const row = alloc.seat.rowIdentifier;
66	      if (!allocatedRowPositions.has(row)) {
67	        allocatedRowPositions.set(row, []);
68	      }
69	      allocatedRowPositions.get(row)!.push(alloc.seat.positionInRow);
70	    }
71	
72	    let chosenSeat = null;
73	
74	    // Try contiguous preference: find a non-accessible seat adjacent to an existing allocation
75	    if (nonAccessible.length > 0 && allocatedRowPositions.size > 0) {
76	      for (const seat of nonAccessible) {
77	        const positions = allocatedRowPositions.get(seat.rowIdentifier);
78	        if (positions) {
79	          const isAdjacent = positions.some(
80	            (pos) => Math.abs(pos - seat.positionInRow) === 1,
81	          );
82	          if (isAdjacent) {
83	            chosenSeat = seat;
84	            break;
85	          }
86	        }
87	      }
88	
89	      // If no adjacent seat found, try any seat in an already-occupied row
90	      if (!chosenSeat) {
91	        for (const seat of nonAccessible) {
92	          if (allocatedRowPositions.has(seat.rowIdentifier)) {
93	            chosenSeat = seat;
94	            break;
95	          }
96	        }
97	      }
98	    }
99	
100	    // Fall back to first available non-accessible seat
101	    if (!chosenSeat && nonAccessible.length > 0) {
102	      chosenSeat = nonAccessible[0];
103	    }
104	
105	    // Use a released ADA seat if available
106	    if (!chosenSeat && accessible.length > 0) {
107	      chosenSeat = accessible[0];
108	    }
109	
110	    // Absolute last resort: use an unreleased ADA seat (e.g. room is otherwise full)
111	    if (!chosenSeat && unreleasedAda.length > 0) {
112	      logger.warn({ sessionId, roomId }, 'Using unreleased ADA seat as last resort');
113	      chosenSeat = unreleasedAda[0];
114	    }
115	
116	    if (!chosenSeat) {
117	      logger.warn({ sessionId, roomId }, 'No suitable seat found');
118	      return null;
119	    }
120	
121	    // Resolve userId from registration (required by SeatAllocation FK)
122	    const registration = await prisma.testRegistration.findUnique({
123	      where: { id: registrationId },
124	      select: { userId: true },
125	    });
126	    const userId = registration?.userId ?? 'unknown';
127	
128	    // Create the allocation
129	    const allocation = await prisma.seatAllocation.create({
130	      data: {
131	        sessionId,
132	        registrationId,
133	        seatId: chosenSeat.id,
134	        userId,
135	        allocatedBy: 'auto',
136	      },
137	      include: {
138	        seat: true,
139	      },
140	    });
141	
142	    logger.info(
143	      { sessionId, registrationId, seatId: chosenSeat.id, seatLabel: chosenSeat.seatLabel },
144	      'Seat allocated',
145	    );
146	
147	    return allocation;
148	  }
149	}
150	
151	export const seatAllocator = new SeatAllocator();
