3	/** Channels supported for outbound message packages */
4	const channelEnum = z.enum(['EMAIL', 'SMS', 'IN_APP', 'ENTERPRISE_IM']);
5	
6	/**
7	 * Channels that can be blacklisted.
8	 * IN_APP is excluded because in-app notifications cannot be externally suppressed.
9	 */
10	const blacklistChannelEnum = z.enum(['EMAIL', 'SMS', 'ENTERPRISE_IM']);
11	
12	export const EnqueueMessageSchema = z.object({
13	  templateId: z.string().uuid().optional(),
14	  recipientAddr: z.string().min(1, 'Recipient address is required'),
15	  recipientUserId: z.string().uuid().optional(),
16	  channel: channelEnum,
17	  subject: z.string().optional(),
18	  variables: z.record(z.string()).optional(),
19	});
20	
21	export const UpdateDeliverySchema = z.object({
22	  status: z.enum(['DELIVERED', 'FAILED', 'MANUALLY_SENT']),
23	  failureReason: z.string().optional(),
24	});
25	
26	export const AddBlacklistSchema = z.object({
27	  address: z.string().min(1, 'Address is required'),
28	  channel: blacklistChannelEnum,
29	  reason: z.string().optional(),
30	  userId: z.string().uuid().optional(),
31	});
32	
33	export const ListMessagesQuerySchema = z.object({
34	  page: z.coerce.number().int().positive().optional(),
35	  pageSize: z.coerce.number().int().positive().max(100).optional(),
36	  status: z.string().optional(),
37	  channel: z.string().optional(),
38	  recipientUserId: z.string().uuid().optional(),
39	});
40	
41	export const ListBlacklistQuerySchema = z.object({
42	  page: z.coerce.number().int().positive().optional(),
43	  pageSize: z.coerce.number().int().positive().max(100).optional(),
44	  channel: z.string().optional(),
45	});
46	
47	export const UpdateQuietHoursSchema = z.object({
48	  timezone: z.string().min(1),
49	  quietStartHr: z.number().int().min(0).max(23),
50	  quietEndHr: z.number().int().min(0).max(23),
51	  isGlobal: z.boolean().optional(),
52	});
53	
54	export type EnqueueMessageBody = z.infer<typeof EnqueueMessageSchema>;
55	export type UpdateDeliveryBody = z.infer<typeof UpdateDeliverySchema>;
56	export type AddBlacklistBody = z.infer<typeof AddBlacklistSchema>;
57	export type ListMessagesQuery = z.infer<typeof ListMessagesQuerySchema>;
58	export type ListBlacklistQuery = z.infer<typeof ListBlacklistQuerySchema>;
59	export type UpdateQuietHoursBody = z.infer<typeof UpdateQuietHoursSchema>;
