160	export const registerForSession = asyncHandler(async (req: Request, res: Response) => {
161	  const { userId: bodyUserId } = req.body as RegisterForSessionBody;
162	  const isPrivileged = req.userRoles?.some(
163	    (r) => r === ROLES.SYSTEM_ADMIN || r === ROLES.TEST_PROCTOR,
164	  ) ?? false;
165	  // Security: non-privileged users can only register themselves
166	  const userId = isPrivileged ? bodyUserId : req.userId;
167	  const result = await testCenterService.registerForSession(req.params.id, userId);
168	  res.status(201).json(created(result));
169	});
170	
171	export const cancelRegistration = asyncHandler(async (req: Request, res: Response) => {
172	  const isPrivileged = req.userRoles?.some(
173	    (r) => r === ROLES.SYSTEM_ADMIN || r === ROLES.TEST_PROCTOR,
174	  ) ?? false;
175	  // Security: non-privileged users can only cancel their own registration
176	  const userId = isPrivileged ? ((req.query.userId as string) ?? req.userId) : req.userId;
177	  await testCenterService.cancelRegistration(req.params.id, userId, req.userId);
178	  res.status(204).send();
179	});
