1	/**
2	 * Backward-compatible synchronous auth middleware.
3	 *
4	 * Unlike the new async `authenticate` (which hits the DB to refresh user data),
5	 * this version is session-only: it validates the session is present and not
6	 * expired, then populates req.userId / req.userRoles from session data.
7	 *
8	 * Used by module routes that were built before the async authenticate was
9	 * introduced. New routes should use authenticate from './authenticate'.
10	 */
11	import type { Request, Response, NextFunction } from 'express';
12	import { UnauthorizedError } from '../shared/errors';
13	
14	const SESSION_INACTIVITY_MS = 30 * 60 * 1000; // 30 minutes
15	
16	export function requireAuth(req: Request, _res: Response, next: NextFunction): void {
17	  const session = req.session;
18	
19	  if (!session?.userId) {
20	    // Throw synchronously so callers using expect(() => requireAuth(...)).toThrow() work
21	    throw new UnauthorizedError('No active session');
22	  }
23	
24	  try {
25	
26	    // Inactivity timeout check — if lastActivity is undefined (first request
27	    // after login before the field was set), treat as fresh.
28	    const lastActivity = session.lastActivity ?? session.lastActivityAt;
29	    if (lastActivity !== undefined && Date.now() - lastActivity > SESSION_INACTIVITY_MS) {
30	      session.destroy(() => {});
31	      next(new UnauthorizedError('Session expired due to inactivity'));
32	      return;
33	    }
34	
35	    // Populate backward-compat request fields from session
36	    req.userId = session.userId;
37	    req.userRoles = (session.userRoles ?? session.roles ?? []) as string[];
38	
39	    // Update activity timestamp
40	    session.lastActivity = Date.now();
41	    if (session.lastActivityAt !== undefined) {
42	      session.lastActivityAt = Date.now();
43	    }
44	
45	    next();
46	  } catch (err) {
47	    next(err);
48	  }
49	}
