1	/**
2	 * Backward-compatible RBAC middleware.
3	 *
4	 * These versions use req.userRoles (populated by requireAuth from session data)
5	 * rather than req.user.roles (populated by the async authenticate middleware).
6	 *
7	 * New routes should use authorize.ts (in-memory checks after authenticate).
8	 */
9	import type { Request, Response, NextFunction, RequestHandler } from 'express';
10	import { ForbiddenError } from '../shared/errors';
11	import { prisma } from '../config/database';
12	
13	/**
14	 * Synchronous role check against req.userRoles.
15	 * Throws ForbiddenError synchronously if the user doesn't have any of the
16	 * listed roles (compatible with routes that aren't wrapped in asyncHandler).
17	 */
18	export function requireRole(...allowedRoles: string[]): RequestHandler {
19	  return (req: Request, _res: Response, next: NextFunction): void => {
20	    const userRoles: string[] = req.userRoles ?? [];
21	    const hasRole = allowedRoles.some((r) => userRoles.includes(r));
22	    if (!hasRole) {
23	      throw new ForbiddenError(`Requires one of roles: ${allowedRoles.join(', ')}`);
24	    }
25	    next();
26	  };
27	}
28	
29	/**
30	 * Async permission check that queries role_permissions for the user's roles.
31	 * @param resource  e.g. 'lease'
32	 * @param action    e.g. 'read'
33	 */
34	export function requirePermission(resource: string, action: string): RequestHandler {
35	  return async (req: Request, _res: Response, next: NextFunction): Promise<void> => {
36	    try {
37	      const userRoles: string[] = req.userRoles ?? [];
38	      if (userRoles.length === 0) {
39	        next(new ForbiddenError('No roles assigned'));
40	        return;
41	      }
42	
43	      const match = await prisma.rolePermission.findFirst({
44	        where: {
45	          role: { name: { in: userRoles as any } },
46	          permission: { resource, action },
47	        },
48	      });
49	
50	      if (!match) {
51	        next(new ForbiddenError(`Missing permission: ${resource}:${action}`));
52	        return;
53	      }
54	
55	      next();
56	    } catch (err) {
57	      next(err);
58	    }
59	  };
60	}
61	
62	/**
63	 * Re-export the new in-memory permission check under an alias.
64	 */
65	export { requirePermission as requirePerm } from './authorize';
