57	// ─── Report Definitions ─────────────────────────────────────────────
58	
59	async function createDefinition(data: CreateReportDefinitionBody, actorId: string) {
60	  const definition = await prisma.reportDefinition.create({
61	    data: {
62	      name: data.name,
63	      description: data.description,
64	      frequency: data.frequency as ReportFrequency,
65	      filterJson: data.filterJson as Prisma.InputJsonValue,
66	      pivotConfig: data.pivotConfig as Prisma.InputJsonValue,
67	      createdBy: actorId,
68	    },
69	  });
70	
71	  await auditService.create({
72	    action: 'REPORT_DEFINITION_CREATED',
73	    actorId,
74	    entityType: 'report_definition',
75	    entityId: definition.id,
76	    afterJson: { name: definition.name, frequency: definition.frequency },
77	  });
78	
79	  logger.info({ definitionId: definition.id }, 'Report definition created');
80	  return definition;
81	}
