83	async function listDefinitions(query: { page?: number; pageSize?: number }) {
84	  const { skip, take, page, pageSize } = parsePagination(query);
85	
86	  const [definitions, total] = await Promise.all([
87	    prisma.reportDefinition.findMany({
88	      where: { isActive: true },
89	      skip,
90	      take,
91	      orderBy: { createdAt: 'desc' },
92	      include: {
93	        _count: { select: { reports: true } },
94	      },
95	    }),
96	    prisma.reportDefinition.count({ where: { isActive: true } }),
97	  ]);
98	
99	  return { data: definitions, meta: buildMeta(total, page, pageSize) };
100	}
