102	async function getDefinition(id: string) {
103	  const definition = await prisma.reportDefinition.findUnique({
104	    where: { id },
105	    include: {
106	      _count: { select: { reports: true } },
107	    },
108	  });
109	
110	  if (!definition) {
111	    throw new NotFoundError('Report definition not found');
112	  }
113	
114	  return definition;
