117	async function updateDefinition(
118	  id: string,
119	  data: UpdateReportDefinitionBody,
120	  actorId?: string,
121	) {
122	  const existing = await prisma.reportDefinition.findUnique({ where: { id } });
123	  if (!existing) {
124	    throw new NotFoundError('Report definition not found');
125	  }
