127	  const definition = await prisma.reportDefinition.update({
128	    where: { id },
129	    data: {
130	      ...(data.name !== undefined && { name: data.name }),
131	      ...(data.description !== undefined && { description: data.description }),
132	      ...(data.frequency !== undefined && { frequency: data.frequency as ReportFrequency }),
133	      ...(data.filterJson !== undefined && { filterJson: data.filterJson as Prisma.InputJsonValue }),
134	      ...(data.pivotConfig !== undefined && { pivotConfig: data.pivotConfig as Prisma.InputJsonValue }),
135	      ...(data.isActive !== undefined && { isActive: data.isActive }),
136	    },
137	  });
138	
139	  await auditService.create({
140	    action: 'REPORT_DEFINITION_UPDATED',
141	    actorId: actorId,
142	    entityType: 'report_definition',
143	    entityId: id,
144	    beforeJson: { name: existing.name, frequency: existing.frequency, isActive: existing.isActive },
145	    afterJson: { name: definition.name, frequency: definition.frequency, isActive: definition.isActive },
146	  });
147	
148	  logger.info({ definitionId: definition.id }, 'Report definition updated');
149	  return definition;
150	}
