152	// ─── Reports ────────────────────────────────────────────────────────
153	
154	async function generateReport(
155	  definitionId: string,
156	  periodStart: string,
157	  periodEnd: string,
158	  actorId: string,
159	) {
160	  const definition = await prisma.reportDefinition.findUnique({
161	    where: { id: definitionId },
162	  });
163	
164	  if (!definition) {
165	    throw new NotFoundError('Report definition not found');
166	  }
167	
168	  const start = new Date(periodStart);
169	  const end = new Date(periodEnd);
170	
171	  if (start >= end) {
172	    throw new BadRequestError('periodStart must be before periodEnd');
173	  }
174	
175	  // Create the report in GENERATING status
176	  const report = await prisma.report.create({
177	    data: {
178	      definitionId,
179	      periodStart: start,
180	      periodEnd: end,
181	      status: 'GENERATING',
182	      createdBy: actorId,
183	    },
184	  });
185	
186	  try {
187	    // Query MetricValues for the period, grouped by property and metric type
188	    const metricValues = await prisma.metricValue.findMany({
189	      where: {
190	        periodStart: { gte: start },
191	        periodEnd: { lte: end },
192	      },
193	      include: {
194	        property: {
195	          include: {
196	            community: {
197	              include: {
198	                region: true,
199	              },
200	            },
201	          },
202	        },
203	        metricDefinitionVersion: {
204	          include: {
205	            metricDefinition: true,
206	          },
207	        },
208	      },
209	      orderBy: { calculatedAt: 'desc' },
210	    });
211	
212	    // Build data JSON grouped by property and metric type
213	    const dataByProperty: Record<string, any> = {};
214	    const versionIdsUsed = new Set<string>();
215	
216	    for (const mv of metricValues) {
217	      const propId = mv.propertyId;
218	      const metricType = mv.metricDefinitionVersion.metricDefinition.metricType;
219	      const versionId = mv.metricDefinitionVersionId;
220	
221	      versionIdsUsed.add(versionId);
222	
223	      if (!dataByProperty[propId]) {
224	        dataByProperty[propId] = {
225	          propertyId: propId,
226	          propertyName: mv.property.name,
227	          communityName: mv.property.community.name,
228	          regionName: mv.property.community.region.name,
229	          metrics: {},
230	        };
231	      }
232	
233	      if (!dataByProperty[propId].metrics[metricType]) {
234	        dataByProperty[propId].metrics[metricType] = [];
235	      }
236	
237	      dataByProperty[propId].metrics[metricType].push({
238	        value: mv.value.toString(),
239	        calculatedAt: mv.calculatedAt.toISOString(),
240	        periodStart: mv.periodStart.toISOString(),
241	        periodEnd: mv.periodEnd.toISOString(),
242	        versionId,
243	      });
244	    }
245	
246	    const dataJson = Object.values(dataByProperty);
247	
248	    // Lock metric definition versions used
249	    const versionIds = Array.from(versionIdsUsed);
250	    if (versionIds.length > 0) {
251	      await prisma.metricDefinitionVersion.updateMany({
252	        where: { id: { in: versionIds } },
253	        data: {
254	          isLocked: true,
255	          lockedAt: new Date(),
256	          lockedByReportId: report.id,
257	        },
258	      });
259	    }
260	
261	    // Create ReportMetricSnapshot entries
262	    if (versionIds.length > 0) {
263	      await prisma.reportMetricSnapshot.createMany({
264	        data: versionIds.map((versionId) => ({
265	          reportId: report.id,
266	          metricDefinitionVersionId: versionId,
267	        })),
268	      });
269	    }
270	
271	    // Update report with data and PUBLISHED status
272	    const updatedReport = await prisma.report.update({
273	      where: { id: report.id },
274	      data: {
275	        dataJson: dataJson as unknown as Prisma.InputJsonValue,
276	        status: 'PUBLISHED',
277	        generatedAt: new Date(),
278	      },
279	      include: {
280	        definition: true,
281	        metricSnapshots: true,
282	      },
283	    });
284	
285	    await auditService.create({
286	      action: 'REPORT_PUBLISHED',
287	      actorId,
288	      entityType: 'report',
289	      entityId: report.id,
290	      metadata: {
291	        definitionId,
292	        periodStart: start.toISOString(),
293	        periodEnd: end.toISOString(),
294	        lockedVersionCount: versionIds.length,
295	      },
296	    });
297	
298	    logger.info(
299	      { reportId: report.id, definitionId, metricsCount: metricValues.length },
300	      'Report generated successfully',
301	    );
302	
303	    return updatedReport;
304	  } catch (error: any) {
305	    await prisma.report.update({
306	      where: { id: report.id },
307	      data: { status: 'FAILED' },
308	    });
309	
310	    logger.error({ reportId: report.id, error: error.message }, 'Report generation failed');
311	    throw error;
312	  }
313	}
