420	async function shareReport(reportId: string, targetUserId: string, actorId: string) {
421	  const report = await prisma.report.findUnique({ where: { id: reportId } });
422	  if (!report) {
423	    throw new NotFoundError('Report not found');
424	  }
425	
426	  // Check the target user exists
427	  const targetUser = await prisma.user.findUnique({
428	    where: { id: targetUserId },
429	    include: {
430	      roles: {
431	        include: {
432	          role: {
433	            include: {
434	              permissions: {
435	                include: { permission: true },
436	              },
437	            },
438	          },
439	        },
440	      },
441	    },
442	  });
443	
444	  if (!targetUser) {
445	    throw new NotFoundError('Target user not found');
446	  }
447	
448	  // Check the target user has a role with report:read permission
449	  const hasReportReadPermission = targetUser.roles.some((ur) =>
450	    ur.role.permissions.some(
451	      (rp) => rp.permission.resource === 'reports' && rp.permission.action === 'read',
452	    ),
453	  );
454	
455	  if (!hasReportReadPermission) {
456	    throw new ForbiddenError('Cannot share report with user who lacks report read permission');
457	  }
458	
459	  // Upsert to handle re-sharing after revocation
460	  const share = await prisma.reportShare.upsert({
461	    where: {
462	      reportId_userId: {
463	        reportId,
464	        userId: targetUserId,
465	      },
466	    },
467	    update: {
468	      revokedAt: null,
469	      sharedBy: actorId,
470	      sharedAt: new Date(),
471	    },
472	    create: {
473	      reportId,
474	      userId: targetUserId,
475	      sharedBy: actorId,
476	    },
477	  });
478	
479	  await auditService.create({
480	    action: 'REPORT_SHARED',
481	    actorId,
482	    entityType: 'report',
483	    entityId: reportId,
484	    metadata: { targetUserId, shareId: share.id },
485	  });
486	
487	  logger.info({ reportId, targetUserId, actorId }, 'Report shared');
488	  return share;
489	}
