545	
546	async function requestExport(
547	  reportId: string,
548	  format: ExportFormat,
549	  userId: string,
550	) {
551	  // Verify user access to the report
552	  const report = await prisma.report.findUnique({
553	    where: { id: reportId },
554	    include: {
555	      definition: true,
556	      shares: { where: { userId, revokedAt: null } },
557	      creator: { select: { id: true, displayName: true } },
558	    },
559	  });
560	
561	  if (!report) {
562	    throw new NotFoundError('Report not found');
563	  }
564	
565	  const isCreator = report.createdBy === userId;
566	  const hasShare = report.shares.length > 0;
567	  if (!isCreator && !hasShare) {
568	    // Forwarding-prevention: log the attempted export by an unauthorised user.
569	    await auditService.create({
570	      action: 'REPORT_EXPORT_BLOCKED',
571	      actorId: userId,
572	      entityType: 'report',
573	      entityId: reportId,
574	      metadata: { reason: 'no_access', format },
575	    });
576	    throw new ForbiddenError('You do not have access to this report');
577	  }
578	
579	  // Re-validate that the requestor STILL has the export permission at request
580	  // time. This prevents the case where a share was granted, then the user's
581	  // role was downgraded, but the user still tries to export.
582	  const requestorWithRoles = await prisma.user.findUnique({
583	    where: { id: userId },
584	    include: {
585	      roles: {
586	        include: {
587	          role: { include: { permissions: { include: { permission: true } } } },
588	        },
589	      },
590	    },
591	  });
592	
593	  const hasExportPermission = (requestorWithRoles?.roles ?? []).some((ur: any) =>
594	    ur.role.permissions.some(
595	      (rp: any) =>
596	        rp.permission.resource === 'reports' && rp.permission.action === 'export',
597	    ),
598	  );
599	
600	  if (!hasExportPermission) {
601	    await auditService.create({
602	      action: 'REPORT_EXPORT_BLOCKED',
603	      actorId: userId,
604	      entityType: 'report',
605	      entityId: reportId,
606	      metadata: { reason: 'missing_export_permission', format },
607	    });
608	    throw new ForbiddenError('Your role no longer permits report exports');
609	  }
610	
611	  if (report.status !== 'PUBLISHED') {
612	    throw new BadRequestError('Can only export published reports');
613	  }
614	
615	  // Get requesting user's display name
616	  const requestor = await prisma.user.findUnique({
617	    where: { id: userId },
618	    select: { displayName: true },
619	  });
620	
621	  const watermarkText = `${requestor?.displayName ?? 'Unknown'} | ${new Date().toISOString()}`;
622	
623	  // Create the export request
624	  const exportRequest = await prisma.exportRequest.create({
625	    data: {
626	      reportId,
627	      requestedBy: userId,
628	      format,
629	      watermarkText,
630	      status: 'GENERATING',
631	    },
632	  });
633	
634	  try {
635	    // Build export data from report
636	    const reportData = (report.dataJson ?? []) as any[];
637	    const columns = buildExportColumns(reportData);
638	    const rows = buildExportRows(reportData);
639	
640	    const exportData: ExportData = {
641	      title: report.definition.name,
642	      columns,
643	      rows,
644	      metadata: {
645	        generatedAt: report.generatedAt?.toISOString() ?? new Date().toISOString(),
646	        generatedBy: report.creator.displayName,
647	        reportId: report.id,
648	      },
649	    };
650	
651	    const exportOptions: ExportOptions = {
652	      watermarkText,
653	      format,
654	    };
655	
656	    const exporter = getExporter(format);
657	    const buffer = await exporter.export(exportData, exportOptions);
658	
659	    // Ensure exports directory exists
660	    await fs.promises.mkdir(EXPORTS_DIR, { recursive: true });
661	
662	    const ext = getFileExtension(format);
663	    const fileName = `report-${report.id}-${exportRequest.id}.${ext}`;
664	    const filePath = path.join(EXPORTS_DIR, fileName);
665	
666	    await fs.promises.writeFile(filePath, buffer);
667	
668	    // Update export request with file path and READY status
669	    const updatedExport = await prisma.exportRequest.update({
670	      where: { id: exportRequest.id },
671	      data: {
672	        filePath,
673	        status: 'READY',
674	        completedAt: new Date(),
675	      },
676	    });
677	
678	    await auditService.create({
679	      action: 'REPORT_EXPORTED',
680	      actorId: userId,
681	      entityType: 'report',
682	      entityId: reportId,
683	      metadata: {
684	        exportId: exportRequest.id,
685	        format,
686	        watermarkText,
687	      },
688	    });
689	
690	    logger.info(
691	      { exportId: exportRequest.id, reportId, format },
692	      'Report export generated',
693	    );
694	
695	    return updatedExport;
696	  } catch (error: any) {
697	    await prisma.exportRequest.update({
698	      where: { id: exportRequest.id },
699	      data: { status: 'FAILED', completedAt: new Date() },
700	    });
701	
702	    logger.error(
703	      { exportId: exportRequest.id, error: error.message },
704	      'Report export generation failed',
705	    );
706	    throw error;
707	  }
708	}
