710	function buildExportColumns(reportData: any[]): { key: string; label: string }[] {
711	  const columns = [
712	    { key: 'propertyName', label: 'Property' },
713	    { key: 'communityName', label: 'Community' },
714	    { key: 'regionName', label: 'Region' },
715	  ];
716	
717	  // Collect all metric types from data
718	  const metricTypes = new Set<string>();
719	  for (const entry of reportData) {
720	    if (entry.metrics) {
721	      Object.keys(entry.metrics).forEach((mt) => metricTypes.add(mt));
722	    }
723	  }
724	
725	  for (const mt of metricTypes) {
726	    columns.push({ key: `metric_${mt}`, label: mt.replace(/_/g, ' ') });
727	  }
728	
729	  return columns;
730	}
731	
732	function buildExportRows(reportData: any[]): Record<string, any>[] {
733	  const rows: Record<string, any>[] = [];
734	
735	  for (const entry of reportData) {
736	    const row: Record<string, any> = {
737	      propertyName: entry.propertyName,
738	      communityName: entry.communityName,
739	      regionName: entry.regionName,
740	    };
741	
742	    if (entry.metrics) {
743	      for (const [metricType, values] of Object.entries(entry.metrics)) {
744	        const metricArray = values as any[];
745	        // Use the latest value for each metric type
746	        if (metricArray.length > 0) {
747	          row[`metric_${metricType}`] = metricArray[0].value;
748	        }
749	      }
750	    }
751	
752	    rows.push(row);
753	  }
754	
755	  return rows;
756	}
