758	async function downloadExport(exportId: string, userId: string) {
759	  const exportReq = await prisma.exportRequest.findUnique({
760	    where: { id: exportId },
761	    include: {
762	      report: {
763	        include: { shares: { where: { userId, revokedAt: null } } },
764	      },
765	    },
766	  });
767	
768	  if (!exportReq) {
769	    throw new NotFoundError('Export request not found');
770	  }
771	
772	  // Hard rule: only the user who originally requested the export can download
773	  // it. This is the primary forwarding-prevention guard — even if the file is
774	  // posted to a chat, the link won't work for any other user account.
775	  if (exportReq.requestedBy !== userId) {
776	    await auditService.create({
777	      action: 'REPORT_EXPORT_BLOCKED',
778	      actorId: userId,
779	      entityType: 'export_request',
780	      entityId: exportId,
781	      metadata: { reason: 'not_requestor', requestor: exportReq.requestedBy },
782	    });
783	    throw new ForbiddenError('You can only download your own exports');
784	  }
785	
786	  // Re-verify the requestor STILL has access to the underlying report. If
787	  // their share was revoked between request and download, block the download.
788	  const isCreator = exportReq.report.createdBy === userId;
789	  const hasActiveShare = exportReq.report.shares.length > 0;
790	  if (!isCreator && !hasActiveShare) {
791	    await auditService.create({
792	      action: 'REPORT_EXPORT_BLOCKED',
793	      actorId: userId,
794	      entityType: 'export_request',
795	      entityId: exportId,
796	      metadata: { reason: 'share_revoked' },
797	    });
798	    throw new ForbiddenError('Your access to this report has been revoked');
799	  }
800	
801	  if (exportReq.status !== 'READY' || !exportReq.filePath) {
802	    throw new BadRequestError('Export is not ready for download');
803	  }
804	
805	  await auditService.create({
806	    action: 'REPORT_EXPORT_DOWNLOADED',
807	    actorId: userId,
808	    entityType: 'export_request',
809	    entityId: exportId,
810	    metadata: { reportId: exportReq.reportId, format: exportReq.format },
811	  });
812	
813	  return {
814	    filePath: exportReq.filePath,
815	    contentType: getContentType(exportReq.format),
816	    fileName: path.basename(exportReq.filePath),
817	  };
818	}
