856	
857	async function pivotQuery(body: PivotQueryBody) {
858	  const { dimensions, measures, filters } = body;
859	
860	  // Build the where clause for MetricValues
861	  const where: Prisma.MetricValueWhereInput = {};
862	
863	  if (filters?.dateFrom || filters?.dateTo) {
864	    where.periodEnd = {};
865	    if (filters.dateFrom) where.periodEnd.gte = new Date(filters.dateFrom);
866	    if (filters.dateTo) where.periodEnd.lte = new Date(filters.dateTo);
867	  }
868	
869	  if (filters?.regionId) {
870	    where.property = {
871	      ...((where.property as Prisma.PropertyWhereInput) ?? {}),
872	      community: { regionId: filters.regionId },
873	    };
874	  }
875	
876	  if (filters?.communityId) {
877	    where.property = {
878	      ...((where.property as Prisma.PropertyWhereInput) ?? {}),
879	      communityId: filters.communityId,
880	    };
881	  }
882	
883	  if (filters?.metricType) {
884	    where.metricDefinitionVersion = {
885	      metricDefinition: {
886	        metricType: filters.metricType as any,
887	      },
888	    };
889	  }
890	
891	  // Fetch metric values with all needed relations
892	  const metricValues = await prisma.metricValue.findMany({
893	    where,
894	    include: {
895	      property: {
896	        include: {
897	          community: {
898	            include: { region: true },
899	          },
900	        },
901	      },
902	      metricDefinitionVersion: {
903	        include: { metricDefinition: true },
904	      },
905	    },
906	  });
907	
908	  // Group by dimensions and calculate measures in-memory
909	  const groups = new Map<string, { keys: Record<string, string>; values: number[] }>();
910	
911	  for (const mv of metricValues) {
912	    const keyParts: Record<string, string> = {};
913	
914	    for (const dim of dimensions) {
915	      switch (dim) {
916	        case 'region':
917	          keyParts.region = mv.property.community.region.name;
918	          break;
919	        case 'community':
920	          keyParts.community = mv.property.community.name;
921	          break;
922	        case 'property':
923	          keyParts.property = mv.property.name;
924	          break;
925	        case 'metric_type':
926	          keyParts.metric_type = mv.metricDefinitionVersion.metricDefinition.metricType;
927	          break;
928	        case 'month':
929	          keyParts.month = `${mv.periodEnd.getFullYear()}-${String(mv.periodEnd.getMonth() + 1).padStart(2, '0')}`;
930	          break;
931	      }
932	    }
933	
934	    const groupKey = dimensions.map((d) => keyParts[d]).join('|');
935	
936	    if (!groups.has(groupKey)) {
937	      groups.set(groupKey, { keys: keyParts, values: [] });
938	    }
939	
940	    groups.get(groupKey)!.values.push(Number(mv.value));
941	  }
942	
943	  // Calculate measures for each group
944	  const rows: Record<string, any>[] = [];
945	
946	  for (const [, group] of groups) {
947	    const row: Record<string, any> = { ...group.keys };
948	    const vals = group.values;
949	
950	    for (const measure of measures) {
951	      switch (measure) {
952	        case 'avg_value':
953	          row.avg_value = vals.length > 0 ? vals.reduce((a, b) => a + b, 0) / vals.length : 0;
954	          break;
955	        case 'sum_value':
956	          row.sum_value = vals.reduce((a, b) => a + b, 0);
957	          break;
958	        case 'count':
959	          row.count = vals.length;
960	          break;
961	        case 'min_value':
962	          row.min_value = vals.length > 0 ? Math.min(...vals) : 0;
963	          break;
964	        case 'max_value':
965	          row.max_value = vals.length > 0 ? Math.max(...vals) : 0;
966	          break;
967	      }
968	    }
969	
970	    rows.push(row);
971	  }
972	
973	  return { dimensions, measures, rows };
974	}
