976	// ─── Scheduled Generation ───────────────────────────────────────────
977	
978	async function generateScheduledReports(frequency: ReportFrequency) {
979	  const definitions = await prisma.reportDefinition.findMany({
980	    where: {
981	      frequency,
982	      isActive: true,
983	    },
984	  });
985	
986	  logger.info(
987	    { frequency, count: definitions.length },
988	    'Starting scheduled report generation',
989	  );
990	
991	  const now = new Date();
992	  let periodStart: Date;
993	
994	  switch (frequency) {
995	    case 'DAILY':
996	      periodStart = new Date(now.getTime() - 24 * 60 * 60 * 1000);
997	      break;
998	    case 'WEEKLY':
999	      periodStart = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);
1000	      break;
1001	    case 'MONTHLY':
1002	      periodStart = new Date(now.getTime() - 30 * 24 * 60 * 60 * 1000);
1003	      break;
1004	    default:
1005	      return [];
1006	  }
