197	async function runRecalculation(jobId: string, propertyIds?: string[]) {
198	  await prisma.metricCalcJob.update({
199	    where: { id: jobId },
200	    data: { status: 'RUNNING', startedAt: new Date() },
201	  });
202	
203	  try {
204	    const whereProperty: Prisma.PropertyWhereInput = { isActive: true };
205	    if (propertyIds && propertyIds.length > 0) {
206	      whereProperty.id = { in: propertyIds };
207	    }
208	
209	    const properties = await prisma.property.findMany({
210	      where: whereProperty,
211	      include: { listings: true },
212	    });
213	
214	    const now = new Date();
215	    const periodStart = new Date(now.getTime() - 30 * 24 * 60 * 60 * 1000); // 30 days ago
216	    const periodEnd = now;
217	
218	    // Get latest versions for each metric type
219	    const definitions = await prisma.metricDefinition.findMany({
220	      include: {
221	        versions: {
222	          where: { effectiveTo: null },
223	          orderBy: { versionNumber: 'desc' },
224	          take: 1,
225	        },
226	      },
227	    });
228	
229	    const versionMap = new Map<MetricType, string>();
230	    for (const def of definitions) {
231	      if (def.versions.length > 0) {
232	        versionMap.set(def.metricType, def.versions[0].id);
233	      }
234	    }
235	
236	    const metricValues: Prisma.MetricValueCreateManyInput[] = [];
237	
238	    for (const property of properties) {
239	      const input = {
240	        propertyId: property.id,
241	        listings: property.listings,
242	        periodStart,
243	        periodEnd,
244	        totalUnits: property.totalUnits,
245	      };
246	
247	      const results = metricEngine.calculateAll(input as any);
248	
249	      for (const [metricType, result] of results.entries()) {
250	        const versionId = versionMap.get(metricType);
251	        if (!versionId) continue;
252	
253	        metricValues.push({
254	          propertyId: property.id,
255	          metricDefinitionVersionId: versionId,
256	          value: result.value,
257	          calculatedAt: now,
258	          periodStart,
259	          periodEnd,
260	        });
261	      }
262	    }
263	
264	    if (metricValues.length > 0) {
265	      await prisma.metricValue.createMany({ data: metricValues });
266	    }
267	
268	    await prisma.metricCalcJob.update({
269	      where: { id: jobId },
270	      data: { status: 'COMPLETED', completedAt: new Date() },
271	    });
272	
273	    logger.info(
274	      { jobId, propertiesProcessed: properties.length, valuesCreated: metricValues.length },
275	      'Metric recalculation completed',
276	    );
277	  } catch (error: any) {
278	    await prisma.metricCalcJob.update({
279	      where: { id: jobId },
280	      data: { status: 'FAILED', completedAt: new Date(), errorLog: error.message },
281	    });
282	    throw error;
283	  }
284	}
