5	export class SeatAllocator {
6	  /**
7	   * Allocate a seat for a registration within a session.
8	   *
9	   * Rules:
10	   * 1. Only serviceable seats in the room are considered.
11	   * 2. Accessible seats are reserved for accessibility needs - skip them
12	   *    unless no other seats are available.
13	   * 3. Prefer a seat in a row that already has allocations for this session
14	   *    (contiguous/adjacent seating preference).
15	   * 4. If no adjacent seat is possible, pick the first available non-accessible seat.
16	   */
17	  async allocateSeats(
18	    sessionId: string,
19	    registrationId: string,
20	    roomId: string,
21	  ) {
22	    // Get all serviceable seats ordered by row then position
23	    const allSeats = await prisma.testSeat.findMany({
24	      where: { roomId, isServiceable: true },
25	      orderBy: [{ rowIdentifier: 'asc' }, { positionInRow: 'asc' }],
26	    });
27	
28	    // Get already-allocated seat IDs for this session
29	    const existingAllocations = await prisma.seatAllocation.findMany({
30	      where: { sessionId },
31	      select: { seatId: true, seat: { select: { rowIdentifier: true, positionInRow: true } } },
32	    });
33	
34	    const allocatedSeatIds = new Set(existingAllocations.map((a) => a.seatId));
35	
36	    // Filter out already-allocated seats
37	    const availableSeats = allSeats.filter((s) => !allocatedSeatIds.has(s.id));
38	
39	    if (availableSeats.length === 0) {
40	      logger.warn({ sessionId, roomId }, 'No available seats for allocation');
41	      return null;
42	    }
43	
44	    // Check which accessible seats have an AdaSeatRelease for this session
45	    // ADA seats are held unless an explicit release record exists for this session.
46	    const adaReleases = await prisma.adaSeatRelease.findMany({
47	      where: { sessionId },
48	      select: { seatId: true },
49	    });
50	    const releasedAdaSeatIds = new Set(adaReleases.map((r) => r.seatId));
51	
52	    // Separate non-accessible and accessible-but-released seats (usable by anyone)
53	    const nonAccessible = availableSeats.filter((s) => !s.isAccessible);
54	    // Accessible seats are only available to general allocation if explicitly released
55	    const accessible = availableSeats.filter(
56	      (s) => s.isAccessible && releasedAdaSeatIds.has(s.id),
57	    );
58	    // Unreleased ADA seats are last resort only when nothing else is available
59	    const unreleasedAda = availableSeats.filter(
60	      (s) => s.isAccessible && !releasedAdaSeatIds.has(s.id),
61	    );
62	
63	    // Build a set of rows that already have allocations in this session
64	    const allocatedRowPositions = new Map<string, number[]>();
65	    for (const alloc of existingAllocations) {
66	      const row = alloc.seat.rowIdentifier;
67	      if (!allocatedRowPositions.has(row)) {
68	        allocatedRowPositions.set(row, []);
69	      }
70	      allocatedRowPositions.get(row)!.push(alloc.seat.positionInRow);
71	    }
72	
73	    let chosenSeat = null;
74	
75	    // Try contiguous preference: find a non-accessible seat adjacent to an existing allocation
76	    if (nonAccessible.length > 0 && allocatedRowPositions.size > 0) {
77	      for (const seat of nonAccessible) {
78	        const positions = allocatedRowPositions.get(seat.rowIdentifier);
79	        if (positions) {
80	          const isAdjacent = positions.some(
81	            (pos) => Math.abs(pos - seat.positionInRow) === 1,
82	          );
83	          if (isAdjacent) {
84	            chosenSeat = seat;
85	            break;
86	          }
87	        }
88	      }
89	
90	      // If no adjacent seat found, try any seat in an already-occupied row
91	      if (!chosenSeat) {
92	        for (const seat of nonAccessible) {
93	          if (allocatedRowPositions.has(seat.rowIdentifier)) {
94	            chosenSeat = seat;
95	            break;
96	          }
97	        }
98	      }
99	    }
100	
101	    // Fall back to first available non-accessible seat
102	    if (!chosenSeat && nonAccessible.length > 0) {
103	      chosenSeat = nonAccessible[0];
104	    }
105	
106	    // Use a released ADA seat if available
107	    if (!chosenSeat && accessible.length > 0) {
108	      chosenSeat = accessible[0];
109	    }
110	
111	    // Absolute last resort: use an unreleased ADA seat (e.g. room is otherwise full).
112	    // ADA_STRICT_MODE=true: skip this fallback and preserve accessible seating.
113	    // Default (false): soft fallback — consistent with prior behavior.
114	    if (!chosenSeat && unreleasedAda.length > 0 && !env.ADA_STRICT_MODE) {
115	      logger.warn({ sessionId, roomId }, 'Using unreleased ADA seat as last resort');
116	      chosenSeat = unreleasedAda[0];
117	    }
118	
119	    if (!chosenSeat) {
120	      logger.warn({ sessionId, roomId }, 'No suitable seat found');
121	      return null;
122	    }
123	
124	    // Resolve userId from registration (required by SeatAllocation FK)
125	    const registration = await prisma.testRegistration.findUnique({
126	      where: { id: registrationId },
127	      select: { userId: true },
128	    });
129	    const userId = registration?.userId ?? 'unknown';
130	
131	    // Create the allocation
132	    const allocation = await prisma.seatAllocation.create({
133	      data: {
134	        sessionId,
135	        registrationId,
136	        seatId: chosenSeat.id,
137	        userId,
138	        allocatedBy: 'auto',
139	      },
140	      include: {
141	        seat: true,
142	      },
143	    });
144	
145	    logger.info(
146	      { sessionId, registrationId, seatId: chosenSeat.id, seatLabel: chosenSeat.seatLabel },
147	      'Seat allocated',
148	    );
149	
150	    return allocation;
151	  }
152	}
153	
154	export const seatAllocator = new SeatAllocator();
