1	/**
2	 * Authentication middleware.
3	 *
4	 * 1. Validates that an active express-session exists with a userId.
5	 * 2. Enforces 30-minute sliding inactivity timeout.
6	 * 3. Loads the user + roles + permissions from DB (mass-assignment-safe SELECT).
7	 * 4. Populates req.user (AuthenticatedUser) for downstream use.
8	 * 5. Populates req.userId / req.userRoles for backward-compatible controllers.
9	 * 6. Caches roles and permissions in the session to reduce DB queries on
10	 *    permission-only checks (the full user is always re-fetched to catch
11	 *    deactivation in real time).
12	 */
13	import type { Request, Response, NextFunction } from 'express';
14	import { UnauthorizedError } from '../errors';
15	import { env } from '../config/env';
16	import { prisma } from '../config/database';
17	import type { RoleName, PermissionKey } from '../domain/roles';
18	
19	export async function authenticate(
20	  req: Request,
21	  _res: Response,
22	  next: NextFunction,
23	): Promise<void> {
24	  try {
25	    // --- 1. Session presence ------------------------------------------------
26	    const userId = req.session?.userId;
27	    if (!userId) {
28	      throw new UnauthorizedError('No active session');
29	    }
30	
31	    // --- 2. Inactivity timeout (30 min sliding window) ----------------------
32	    const now = Date.now();
33	    const lastActivity = req.session.lastActivityAt ?? req.session.lastActivity ?? 0;
34	    const elapsed = now - lastActivity;
35	
36	    if (elapsed > env.SESSION_INACTIVITY_MS) {
37	      req.session.destroy(() => {});
38	      throw new UnauthorizedError('Session expired due to inactivity');
39	    }
40	
41	    // --- 3. Load user from DB (mass-assignment-safe explicit select) ---------
42	    const user = await prisma.user.findUnique({
43	      where: { id: userId, isActive: true },
44	      select: {
45	        id: true,
46	        username: true,
47	        displayName: true,
48	        email: true,
49	        roles: {
50	          select: {
51	            role: {
52	              select: {
53	                name: true,
54	                permissions: {
55	                  select: {
56	                    permission: {
57	                      select: { resource: true, action: true },
58	                    },
59	                  },
60	                },
61	              },
62	            },
63	          },
64	        },
65	      },
66	    });
67	
68	    if (!user) {
69	      req.session.destroy(() => {});
70	      throw new UnauthorizedError('User account not found or deactivated');
71	    }
72	
73	    // --- 4. Build roles & permissions arrays --------------------------------
74	    const roles = user.roles.map((ur) => ur.role.name as RoleName);
75	    const permissionSet = new Set<PermissionKey>();
76	    for (const ur of user.roles) {
77	      for (const rp of ur.role.permissions) {
78	        permissionSet.add(
79	          `${rp.permission.resource}:${rp.permission.action}` as PermissionKey,
80	        );
81	      }
82	    }
83	    const permissions = Array.from(permissionSet);
84	
85	    // --- 5. Populate req.user (new pattern) ---------------------------------
86	    req.user = {
87	      id: user.id,
88	      username: user.username,
89	      displayName: user.displayName,
90	      email: user.email,
91	      roles,
92	      permissions,
93	    };
94	
95	    // --- 6. Backward-compat for old controllers that use req.userId ----------
96	    req.userId = user.id;
97	    req.userRoles = roles as string[];
98	
99	    // --- 7. Update session with fresh data ----------------------------------
100	    req.session.lastActivityAt = now;
101	    req.session.lastActivity = now;          // compat alias
102	    req.session.roles = roles;
103	    req.session.permissions = permissions;
104	    req.session.userRoles = roles as string[]; // compat alias
105	
106	    next();
107	  } catch (err) {
108	    next(err);
109	  }
110	}
