348	  async registerForSession(sessionId: string, userId: string) {
349	    const session = await prisma.testSession.findUnique({ where: { id: sessionId } });
350	    if (!session) throw new NotFoundError('Test session not found');
351	
352	    if (session.status !== 'SCHEDULED') {
353	      throw new BadRequestError('Can only register for sessions with SCHEDULED status');
354	    }
355	
356	    // Enforce capacity
357	    if (session.currentEnrolled >= session.maxCapacity) {
358	      throw new ConflictError('Session is full. No more registrations allowed.');
359	    }
360	
361	    // Check duplicate registration
362	    const existing = await prisma.testRegistration.findUnique({
363	      where: { sessionId_userId: { sessionId, userId } },
