1	/**
2	 * Auth controller — login, me, logout, touch.
3	 *
4	 * Session semantics:
5	 *   - login:  creates a new session, stores userId + roles + permissions
6	 *   - me:     returns current user profile (authenticate middleware already validated)
7	 *   - logout: destroys the express session, clears cookie
8	 *   - touch:  explicit keep-alive for polling UIs; authenticate already bumps
9	 *             lastActivityAt so this is just a lightweight ping
10	 */
11	import type { Request, Response } from 'express';
12	import { asyncHandler } from '../../utils/asyncHandler';
13	import { sendSuccess, sendNoContent } from '../../utils/response';
14	import { authService } from './auth.service';
15	import type { LoginBody } from './auth.schemas';
16	import type { RoleName, PermissionKey } from '../../domain/roles';
17	import { SESSION_COOKIE_NAME } from '../../config/constants';
18	
19	// ─── POST /auth/login ─────────────────────────────────────────────────
20	export const login = asyncHandler(async (req: Request, res: Response) => {
21	  const { username, password } = req.body as LoginBody;
22	  const ipAddress = req.ip ?? req.socket?.remoteAddress;
23	
24	  const user = await authService.login(username, password, ipAddress);
25	
26	  // Regenerate session ID to prevent session-fixation attacks
27	  await new Promise<void>((resolve, reject) => {
28	    req.session.regenerate((err) => (err ? reject(err) : resolve()));
29	  });
30	
31	  // Populate session
32	  req.session.userId = user.id;
33	  req.session.roles = user.roles.map((r) => r.name) as RoleName[];
34	  req.session.permissions = user.permissions as PermissionKey[];
35	  req.session.lastActivityAt = Date.now();
36	  // Backward-compat aliases
37	  req.session.userRoles = user.roles.map((r) => r.name);
38	  req.session.lastActivity = Date.now();
39	
40	  // Explicitly save before responding (guarantees store write completes)
41	  await new Promise<void>((resolve, reject) => {
42	    req.session.save((err) => (err ? reject(err) : resolve()));
43	  });
44	
45	  sendSuccess(res, user);
46	});
47	
48	// ─── GET /auth/me ─────────────────────────────────────────────────────
49	export const me = asyncHandler(async (req: Request, res: Response) => {
50	  // authenticate middleware already validated session and set req.user,
51	  // but we call the service to get the full profile with employeeId
52	  const userId = req.user?.id ?? req.userId;
53	  const user = await authService.getCurrentUser(userId);
54	  sendSuccess(res, user);
55	});
56	
57	// ─── POST /auth/logout ────────────────────────────────────────────────
58	export const logout = asyncHandler(async (req: Request, res: Response) => {
59	  const userId = req.user?.id ?? req.userId;
60	  const ipAddress = req.ip ?? req.socket?.remoteAddress;
61	
62	  await authService.logout(userId, ipAddress);
63	
64	  // Destroy the server-side session
65	  await new Promise<void>((resolve, reject) => {
66	    req.session.destroy((err) => (err ? reject(err) : resolve()));
67	  });
68	
69	  // Clear the session cookie
70	  res.clearCookie(SESSION_COOKIE_NAME);
71	
72	  sendSuccess(res, { message: 'Logged out' });
73	});
74	
75	// ─── POST /auth/touch ─────────────────────────────────────────────────
76	// Explicit activity ping. authenticate middleware already bumps lastActivityAt,
77	// so this endpoint just returns 204 to confirm the session is still alive.
78	export const touch = asyncHandler(async (req: Request, res: Response) => {
79	  sendNoContent(res);
80	});
81	
