 * Security hardening tests — focused, low-mock coverage of the high-risk
 * behaviors fixed in the audit:
 *
 *   1. Analytics listShares now enforces creator-or-active-share access
 *   2. Metric createVersion refuses to mutate a locked predecessor's effectiveTo
 *   3. ADA_STRICT_MODE defaults to true (requirement-aligned)
 *   4. Audit retention policy is set to 7 years and never invokes delete
 */
import { describe, it, expect, vi, beforeEach } from 'vitest';

// ─── 1. listShares ACL ──────────────────────────────────────────────────────

describe('analyticsService.listShares — ACL', () => {
  const { mockPrisma } = vi.hoisted(() => ({
    mockPrisma: {
      report: { findUnique: vi.fn() },
      reportShare: { findMany: vi.fn() },
      auditLog: { create: vi.fn() },
    },
  }));

  vi.mock('../../../src/config/database', () => ({ prisma: mockPrisma }));
  vi.mock('../../../src/logging/logger', () => ({
    logger: { info: vi.fn(), warn: vi.fn(), error: vi.fn() },
  }));
  vi.mock('../../../src/modules/audit/audit.service', () => ({
    auditService: { create: vi.fn() },
  }));

  beforeEach(() => {
    vi.clearAllMocks();
    mockPrisma.reportShare.findMany.mockResolvedValue([
      { id: 'share-1', userId: 'sharee-1' },
    ]);
  });

  it('rejects unrelated user with NotFoundError (no enumeration disclosure)', async () => {
    const { analyticsService } = await import('../../../src/modules/analytics/analytics.service');
    mockPrisma.report.findUnique.mockResolvedValue({
      id: 'r1',
      createdBy: 'creator-1',
      shares: [], // requesting user has no active share
    });

    await expect(
      analyticsService.listShares('r1', 'unrelated-user'),
    ).rejects.toMatchObject({ statusCode: 404 });
  });

  it('allows creator', async () => {
    const { analyticsService } = await import('../../../src/modules/analytics/analytics.service');
    mockPrisma.report.findUnique.mockResolvedValue({
      id: 'r1',
      createdBy: 'creator-1',
      shares: [],
    });

    const res = await analyticsService.listShares('r1', 'creator-1');
    expect(res).toHaveLength(1);
  });

  it('allows an active sharee', async () => {
    const { analyticsService } = await import('../../../src/modules/analytics/analytics.service');
    mockPrisma.report.findUnique.mockResolvedValue({
      id: 'r1',
      createdBy: 'creator-1',
      shares: [{ id: 'sharee-self' }],
    });

    const res = await analyticsService.listShares('r1', 'sharee-1');
